// NewBluetoothLeAudioStub creates a server-side IBluetoothLeAudio wrapping the given
// server implementation. The returned value satisfies IBluetoothLeAudio
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewBluetoothLeAudioStub(
	impl IBluetoothLeAudioServer,
) IBluetoothLeAudio {
	wrapper := &bluetoothLeAudioStubWrapper{impl: impl}
	stub := &BluetoothLeAudioStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
